changeSet.sql:
CREATE TABLE review_competencies (
    id UUID PRIMARY KEY,
    tenant_id UUID NOT NULL,
    review_id UUID NOT NULL,
    competency_name VARCHAR(200) NOT NULL,
    category VARCHAR(100),
    rating DECIMAL(3,2),
    comments TEXT,
    created_at TIMESTAMP NOT NULL,
    updated_at TIMESTAMP NOT NULL,
    version BIGINT
);

CREATE INDEX idx_review_competencies_tenant ON review_competencies(tenant_id);
CREATE INDEX idx_review_competencies_review ON review_competencies(review_id);

ALTER TABLE review_competencies ADD CONSTRAINT fk_review_competencies_tenant FOREIGN KEY (tenant_id) REFERENCES tenants(id) ON DELETE CASCADE;
ALTER TABLE review_competencies ADD CONSTRAINT fk_review_competencies_review FOREIGN KEY (review_id) REFERENCES performance_reviews(id) ON DELETE CASCADE;
